previewCss:
.darma-loader-darma-custom-122 {
  color: #7c3aed;
width: 49px;
aspect-ratio: 1;
--c: no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color));
background:
var(--c) 0% 100%,
var(--c) 50% 100%,
var(--c) 100% 100%;
animation: darma-loader-darma-custom-122-l2 1s infinite linear;
}
@keyframes darma-loader-darma-custom-122-l2 {
0% {background-size: 20% 100%,20% 100%,20% 100%}
20% {background-size: 20% 60% ,20% 100%,20% 100%}
40% {background-size: 20% 80% ,20% 60% ,20% 100%}
60% {background-size: 20% 100%,20% 80% ,20% 60% }
80% {background-size: 20% 100%,20% 100%,20% 80% }
100%{background-size: 20% 100%,20% 100%,20% 100%}
}

